# Updated code to replace ScriptProperties with PropertiesService
class TemplateManager:
    def __init__(self):
        self.properties = PropertiesService.getScriptProperties()

    def set_property(self, key, value):
        self.properties.setProperty(key, value)

    def get_property(self, key):
        return self.properties.getProperty(key)

    def delete_property(self, key):
        self.properties.deleteProperty(key)

    def create_template(self, template_name, rules):
        self.set_property(template_name, rules)

    def get_template(self, template_name):
        return self.get_property(template_name)

    def delete_template(self, template_name):
        self.delete_property(template_name)

# Example usage
template_manager = TemplateManager()
template_manager.create_template("exampleTemplate", "some business logic")
print(template_manager.get_template("exampleTemplate"))
template_manager.delete_template("exampleTemplate")
